package kyo.ffi.codegen.emitters

import EmitterFixtures.*
import kyo.ffi.codegen.model.*

class JsEmitterTest extends kyo.test.Test[Any]:

    // -------------------------------------------------------------------------
    // Section 1: header / companion basics
    // -------------------------------------------------------------------------

    "emits an AUTO-GENERATED banner, package clause, and JS imports" in {
        val spec = mkTrait(
            "Simple",
            "simple",
            List(mkMethod("noop", "noop", Nil, ReturnShape.Void))
        )
        val src = JsEmitter.emit(spec)
        assert(src.startsWith("// AUTO-GENERATED by kyo-ffi-codegen"))
        assert(src.contains("package kyo.example"))
        assert(src.contains("import scala.scalajs.js"))
        assert(src.contains("import scala.scalajs.js.annotation.*"))
        assert(src.contains("import scala.scalajs.js.typedarray.*"))
        assert(src.contains("import scala.scalajs.reflect.annotation.EnableReflectiveInstantiation"))
        assert(src.contains("import kyo.ffi.*"))
        assert(src.contains(
            "import kyo.ffi.internal.{AbiCheck, JsRawSegment, KoffiFacade, KoffiFn, NativeLoader, StructAbiCheck}"
        ))
    }

    "impl class is annotated with @EnableReflectiveInstantiation so Ffi.load can reach it" in {
        val spec = mkTrait(
            "Simple",
            "simple",
            List(mkMethod("noop", "noop", Nil, ReturnShape.Void))
        )
        val src = JsEmitter.emit(spec)
        assert(src.contains("@EnableReflectiveInstantiation final class SimpleImpl extends Simple:"))
    }

    "companion calls AbiCheck.verify and loads via NativeLoader.jsResolve" in {
        val spec = mkTrait(
            "TcpBindings",
            "kyo_tcp",
            List(mkMethod("tcpClose", "tcp_close", List(ParamSpec("fd", TypeRef.IntT)), ReturnShape.Void))
        )
        val src = JsEmitter.emit(spec)
        assert(src.contains("""AbiCheck.verify(1, "kyo.example.TcpBindings")"""))
        assert(src.contains("""NativeLoader.jsResolve("kyo_tcp")"""))
        assert(src.contains("private val facade = KoffiFacade.load("))
    }

    // -------------------------------------------------------------------------
    // Section 2: KoffiFn emission per-method
    // -------------------------------------------------------------------------

    "emits a KoffiFn with scalaName, cSymbol, result, and arg types" in {
        val spec = mkTrait(
            "TcpBindings",
            "kyo_tcp",
            List(
                mkMethod(
                    "tcpClose",
                    "tcp_close",
                    List(ParamSpec("fd", TypeRef.IntT)),
                    ReturnShape.Void
                )
            )
        )
        val src = JsEmitter.emit(spec)
        assert(src.contains("""KoffiFn("tcpClose", "tcp_close", "void", Seq[js.Any]("int".asInstanceOf[js.Any]))"""))
    }

    "multi-value return appends `<T>*` trailing entries to the KoffiFn args list" in {
        val cr = StructSpec(
            "kyo.example.ConnectResult",
            "ConnectResult",
            List(StructField("fd", TypeRef.IntT), StructField("pending", TypeRef.IntT)),
            packed = false
        )
        val spec = mkTrait(
            "TcpBindings",
            "kyo_tcp",
            List(mkMethod(
                "tcpConnect",
                "tcp_connect",
                List(ParamSpec("host", TypeRef.StringT), ParamSpec("port", TypeRef.IntT)),
                ReturnShape.MultiValue(cr),
                blocking = true
            )),
            structs = List(cr)
        )
        val src = JsEmitter.emit(spec)
        assert(src.contains(
            """KoffiFn("tcpConnect", "tcp_connect", "int", Seq[js.Any]("string".asInstanceOf[js.Any], "int".asInstanceOf[js.Any], "int*".asInstanceOf[js.Any]))"""
        ))
    }

    "Buffer params map to \"void*\" in the KoffiFn args" in {
        val spec = mkTrait(
            "TcpBindings",
            "kyo_tcp",
            List(mkMethod(
                "tcpRead",
                "tcp_read",
                List(
                    ParamSpec("fd", TypeRef.IntT),
                    ParamSpec("buf", TypeRef.BufferT(TypeRef.ByteT)),
                    ParamSpec("maxLen", TypeRef.IntT)
                ),
                ReturnShape.Primitive(TypeRef.IntT),
                blocking = true
            ))
        )
        val src = JsEmitter.emit(spec)
        assert(src.contains(
            """KoffiFn("tcpRead", "tcp_read", "int", Seq[js.Any]("int".asInstanceOf[js.Any], "void*".asInstanceOf[js.Any], "int".asInstanceOf[js.Any]))"""
        ))
    }

    // -------------------------------------------------------------------------
    // Section 2b: Boolean return / param / struct field marshalling (C `int` ABI)
    // -------------------------------------------------------------------------

    "Boolean-return method registers koffi result \"int\" (not \"bool\") and converts via != 0" in {
        // The C ABI for a Boolean-typed binding is `int` (1/0). The koffi registration must agree with the
        // Scala-side `.asInstanceOf[Int] != 0` conversion (matching JvmEmitter's JAVA_INT / NativeEmitter's
        // CInt). Registering "bool" while casting to Int mis-marshals the result (the original JS bug).
        val spec = mkTrait(
            "ProbeBindings",
            "kyo_probe",
            List(mkMethod("available", "probe_available", Nil, ReturnShape.Primitive(TypeRef.BooleanT)))
        )
        val src = JsEmitter.emit(spec)
        assert(src.contains("""KoffiFn("available", "probe_available", "int", Seq[js.Any]())"""))
        assert(src.contains("val retVal = facade.available().asInstanceOf[Int]"))
        assert(src.contains("retVal != 0"))
        assert(!src.contains("\"bool\""))
    }

    "Boolean param registers koffi arg \"int\" and passes 1/0" in {
        val spec = mkTrait(
            "FlagBindings",
            "kyo_flag",
            List(mkMethod("setFlag", "set_flag", List(ParamSpec("on", TypeRef.BooleanT)), ReturnShape.Void))
        )
        val src = JsEmitter.emit(spec)
        assert(src.contains("""KoffiFn("setFlag", "set_flag", "void", Seq[js.Any]("int".asInstanceOf[js.Any]))"""))
        assert(src.contains("facade.setFlag(if on then 1 else 0)"))
        assert(!src.contains("\"bool\""))
    }

    "Boolean struct field registers koffi \"int\" and the multi-value out-param uses \"int*\"" in {
        val rr = StructSpec(
            "kyo.example.ReadResult",
            "ReadResult",
            List(StructField("bytesRead", TypeRef.IntT), StructField("eof", TypeRef.BooleanT)),
            packed = false
        )
        val spec = mkTrait(
            "ReadBindings",
            "kyo_read",
            List(mkMethod(
                "readInto",
                "read_into",
                List(ParamSpec("fd", TypeRef.IntT), ParamSpec("buf", TypeRef.BufferT(TypeRef.ByteT))),
                ReturnShape.MultiValue(rr),
                blocking = true
            )),
            structs = List(rr)
        )
        val src = JsEmitter.emit(spec)
        // struct registration: Boolean field → "int"
        assert(src.contains("""js.Dynamic.literal("bytesRead" -> "int".asInstanceOf[js.Any], "eof" -> "int".asInstanceOf[js.Any])"""))
        // out-param koffi type for the Boolean tail field → "int*"
        assert(src.contains("\"int*\".asInstanceOf[js.Any]"))
        // out-cell allocated as an int cell, read and converted via != 0
        assert(src.contains("val eofOut = KoffiFacade.outInt()"))
        assert(src.contains("eofOut.read().asInstanceOf[Int] != 0"))
        assert(!src.contains("\"bool\""))
        assert(!src.contains("\"bool*\""))
    }

    "Boolean callback param/return keep koffi proto \"bool\" (Scala side is a genuine Boolean)" in {
        // Callback (proto) positions are NOT func-ABI positions: the Scala wrapper exchanges a real Boolean
        // with koffi there, so they stay "bool" while func/struct/out-param Booleans become "int". This mirrors
        // JvmEmitter's callbackValueLayout (JAVA_BOOLEAN) vs paramLayout (JAVA_INT) split.
        val spec = mkTrait(
            "PredBindings",
            "kyo_pred",
            List(mkMethod(
                "filter",
                "filter",
                List(
                    ParamSpec("buf", TypeRef.BufferT(TypeRef.ByteT)),
                    ParamSpec("pred", TypeRef.FnPtrT(List(TypeRef.BooleanT), TypeRef.BooleanT))
                ),
                ReturnShape.Void,
                kind = CallbackKind.Transient
            ))
        )
        val src = JsEmitter.emit(spec)
        assert(src.contains("""KoffiFacade.proto("filter_pred_proto", "bool", Seq[String]("bool"))"""))
    }

    // -------------------------------------------------------------------------
    // Section 3: impl-class body, marshalling
    // -------------------------------------------------------------------------

    "primitive-only method body calls facade (no errno capture for plain returns)" in {
        val spec = mkTrait(
            "Math",
            "kyo_math",
            List(
                mkMethod(
                    "add",
                    "add_ints",
                    List(ParamSpec("a", TypeRef.IntT), ParamSpec("b", TypeRef.IntT)),
                    ReturnShape.Primitive(TypeRef.IntT)
                )
            )
        )
        val src = JsEmitter.emit(spec)
        assert(src.contains("def add(a: Int, b: Int)(using kyo.AllowUnsafe): Int ="))
        assert(src.contains("val retVal = facade.add(a, b).asInstanceOf[Int]"))
        assert(!src.contains("val __errno = KoffiFacade.errno()"))
    }

    "Buffer param casts .raw to Uint8Array" in {
        val spec = mkTrait(
            "TcpBindings",
            "kyo_tcp",
            List(
                mkMethod(
                    "tcpRead",
                    "tcp_read",
                    List(
                        ParamSpec("fd", TypeRef.IntT),
                        ParamSpec("buf", TypeRef.BufferT(TypeRef.ByteT)),
                        ParamSpec("maxLen", TypeRef.IntT)
                    ),
                    ReturnShape.Primitive(TypeRef.IntT),
                    blocking = true
                )
            )
        )
        val src = JsEmitter.emit(spec)
        // `Buffer.Raw` unwrap routes through `FfiUnsafe.expect`.
        assert(src.contains(
            """val bufU8 = kyo.ffi.internal.FfiUnsafe.expect[JsRawSegment](buf.raw.asInstanceOf[AnyRef], classOf[JsRawSegment], "JsRawSegment on JS", "kyo.example.TcpBindings", "tcpRead").u8a"""
        ))
        // tcpRead is @Ffi.blocking: the koffi call runs via `BlockingBridge.runAsync` (which dispatches through
        // `KoffiFacade.callAsync`) on a libuv worker; the unwrapped `bufU8` is threaded into the async arg array.
        assert(src.contains(
            """kyo.ffi.internal.BlockingBridge.runAsync(facade, "tcpRead", js.Array[js.Any](fd, bufU8, maxLen), (raw: js.Any) =>"""
        ))
    }

    "multi-value return allocates KoffiFacade.outInt() cells and reads them post-call" in {
        val cr = StructSpec(
            "kyo.example.ConnectResult",
            "ConnectResult",
            List(StructField("fd", TypeRef.IntT), StructField("pending", TypeRef.IntT)),
            packed = false
        )
        val spec = mkTrait(
            "TcpBindings",
            "kyo_tcp",
            List(mkMethod(
                "tcpConnect",
                "tcp_connect",
                List(ParamSpec("host", TypeRef.StringT), ParamSpec("port", TypeRef.IntT)),
                ReturnShape.MultiValue(cr),
                blocking = true
            )),
            structs = List(cr)
        )
        val src = JsEmitter.emit(spec)
        // The out-cell is allocated before the async call so it outlives the call and is read back in the
        // completion callback. tcpConnect is @Ffi.blocking: the koffi return `raw` is marshalled in the callback.
        assert(src.contains("val pendingOut = KoffiFacade.outInt()"))
        assert(src.contains(
            """kyo.ffi.internal.BlockingBridge.runAsync(facade, "tcpConnect", js.Array[js.Any](host, port, pendingOut.buf), (raw: js.Any) =>"""
        ))
        assert(src.contains("val retVal = raw.asInstanceOf[Int]"))
        assert(src.contains("kyo.example.ConnectResult(retVal, pendingOut.read().asInstanceOf[Int])"))
    }

    "Unit-return method calls facade, then `()`, no retVal cast" in {
        val spec = mkTrait(
            "Simple",
            "simple",
            List(mkMethod("close", "do_close", List(ParamSpec("fd", TypeRef.IntT)), ReturnShape.Void))
        )
        val src = JsEmitter.emit(spec)
        assert(src.contains("facade.close(fd)"))
        assert(!src.contains("val retVal"))
    }

    // -------------------------------------------------------------------------
    // Section 3b: callback emission (transient + retained)
    // -------------------------------------------------------------------------

    "transient callback: body passes the raw Scala function directly to the facade call (no register/unregister)" in {
        val spec = mkTrait(
            "SortBindings",
            "kyo_sort",
            List(
                mkMethod(
                    "qsort",
                    "qsort",
                    List(
                        ParamSpec("base", TypeRef.BufferT(TypeRef.ByteT)),
                        ParamSpec("count", TypeRef.IntT),
                        ParamSpec("elemSize", TypeRef.IntT),
                        ParamSpec("cmp", TypeRef.FnPtrT(List(TypeRef.IntT, TypeRef.IntT), TypeRef.IntT))
                    ),
                    ReturnShape.Void,
                    kind = CallbackKind.Transient
                )
            )
        )
        val src = JsEmitter.emit(spec)
        // Signature uses the function type, not a guard.
        assert(src.contains(
            "def qsort(base: Buffer[Byte], count: Int, elemSize: Int, cmp: (Int, Int) => Int)(using kyo.AllowUnsafe): Unit ="
        ))
        // The user callback is wrapped in a safe closure that catches exceptions and returns a typed zero
        // (here `0` for `Int`). The wrapped `cmpSafe` is passed to facade.
        assert(src.contains("val cmpSafe: (Int, Int) => Int = (a0: Int, a1: Int) =>"))
        assert(src.contains("try cmp(a0, a1)"))
        assert(src.contains("catch case t: Throwable =>"))
        assert(src.contains("""kyo.ffi.internal.FfiGenErrors.reportCallbackFailed("kyo.example.SortBindings", "qsort", "transient", t)"""))
        assert(src.contains("facade.qsort(baseU8, count, elemSize, cmpSafe)"))
        // No KoffiFacade.register / unregister calls in the transient body.
        assert(!src.contains("KoffiFacade.register(cmp"))
        assert(!src.contains("KoffiFacade.unregister"))
        // No guard retain on transient.
        assert(!src.contains("asInstanceOf[kyo.ffi.internal.JsGuard]"))
    }

    "transient callback: companion declares the proto up-front and KoffiFn emits KoffiFacade.pointer at the callback slot" in {
        val spec = mkTrait(
            "SortBindings",
            "kyo_sort",
            List(
                mkMethod(
                    "qsort",
                    "qsort",
                    List(
                        ParamSpec("base", TypeRef.BufferT(TypeRef.ByteT)),
                        ParamSpec("count", TypeRef.IntT),
                        ParamSpec("elemSize", TypeRef.IntT),
                        ParamSpec("cmp", TypeRef.FnPtrT(List(TypeRef.IntT, TypeRef.IntT), TypeRef.IntT))
                    ),
                    ReturnShape.Void,
                    kind = CallbackKind.Transient
                )
            )
        )
        val src = JsEmitter.emit(spec)
        // Proto registration in the companion, the Seq[KoffiFn] entry references this handle through KoffiFacade.pointer.
        assert(src.contains(
            """KoffiFacade.proto("qsort_cmp_proto", "int", Seq[String]("int", "int"))"""
        ))
        // KoffiFn entry threads the proto handle via `KoffiFacade.pointer(<protoVal>)` at the callback arg slot.
        assert(src.contains(
            """KoffiFn("qsort", "qsort", "void", Seq[js.Any]("void*".asInstanceOf[js.Any], "int".asInstanceOf[js.Any], "int".asInstanceOf[js.Any], KoffiFacade.pointer(qsort_cmp_proto)))"""
        ))
    }

    "retained callback: body registers the stub, pins it on the guard, and does NOT unregister post-call" in {
        val spec = mkTrait(
            "Epoll",
            "kyo_epoll",
            List(
                mkMethod(
                    "epollAdd",
                    "epoll_add",
                    List(
                        ParamSpec("guard", TypeRef.GuardT),
                        ParamSpec("epfd", TypeRef.IntT),
                        ParamSpec("fd", TypeRef.IntT),
                        ParamSpec("onEvent", TypeRef.FnPtrT(List(TypeRef.IntT), TypeRef.UnitT))
                    ),
                    ReturnShape.Primitive(TypeRef.IntT),
                    kind = CallbackKind.Retained
                )
            )
        )
        val src = JsEmitter.emit(spec)
        assert(src.contains("def epollAdd(guard: Ffi.Guard, epfd: Int, fd: Int, onEvent: Int => Unit)(using kyo.AllowUnsafe): Int ="))
    }

    "retained callback: body registers the handle, schedules close-time unregister on the guard, and does NOT unregister post-call" in {
        val spec = mkTrait(
            "Epoll",
            "kyo_epoll",
            List(
                mkMethod(
                    "epollAdd",
                    "epoll_add",
                    List(
                        ParamSpec("guard", TypeRef.GuardT),
                        ParamSpec("epfd", TypeRef.IntT),
                        ParamSpec("fd", TypeRef.IntT),
                        ParamSpec("onEvent", TypeRef.FnPtrT(List(TypeRef.IntT), TypeRef.UnitT))
                    ),
                    ReturnShape.Primitive(TypeRef.IntT),
                    kind = CallbackKind.Retained
                )
            )
        )
        val src = JsEmitter.emit(spec)
        // Proto registered once in the companion as a private `val`; body forwards the handle into
        // `KoffiFacade.register`'s `js.Any` slot, wrapped in `KoffiFacade.pointer(...)`.
        // The user callback is wrapped in a try/catch and THEN registered with koffi.
        assert(src.contains("val onEventSafe: Int => Unit = (a0: Int) =>"))
        assert(src.contains("""kyo.ffi.internal.FfiGenErrors.reportCallbackFailed("kyo.example.Epoll", "epollAdd", "retained", t)"""))
        assert(src.contains(
            """val onEventH = KoffiFacade.register(onEventSafe, KoffiFacade.pointer(epollAdd_onEvent_proto))"""
        ))
        assert(src.contains(
            "guard.asInstanceOf[kyo.ffi.internal.JsGuard].unsafeRetainCleanup(() => KoffiFacade.unregister(onEventH))"
        ))
        assert(src.contains("facade.epollAdd(epfd, fd, onEventH)"))
        // Retained path: the guard owns unregistration, so no KoffiFacade.unregister in the method body.
        assert(!src.contains("KoffiFacade.unregister(onEventH)\n"))
    }

    "retained callback: companion emits proto + KoffiFn with guard-slot dropped and KoffiFacade.pointer at callback slot" in {
        val spec = mkTrait(
            "Epoll",
            "kyo_epoll",
            List(
                mkMethod(
                    "epollAdd",
                    "epoll_add",
                    List(
                        ParamSpec("guard", TypeRef.GuardT),
                        ParamSpec("epfd", TypeRef.IntT),
                        ParamSpec("fd", TypeRef.IntT),
                        ParamSpec("onEvent", TypeRef.FnPtrT(List(TypeRef.IntT), TypeRef.UnitT))
                    ),
                    ReturnShape.Primitive(TypeRef.IntT),
                    kind = CallbackKind.Retained
                )
            )
        )
        val src = JsEmitter.emit(spec)
        assert(src.contains(
            """KoffiFacade.proto("epollAdd_onEvent_proto", "void", Seq[String]("int"))"""
        ))
        // Guard never crosses the FFI boundary; koffi arg list starts with the int params then the callback proto handle.
        assert(src.contains(
            """KoffiFn("epollAdd", "epoll_add", "int", Seq[js.Any]("int".asInstanceOf[js.Any], "int".asInstanceOf[js.Any], KoffiFacade.pointer(epollAdd_onEvent_proto)))"""
        ))
    }

    "transient callback: source parses under Scala 3" in {
        val spec = mkTrait(
            "SortBindings",
            "kyo_sort",
            List(
                mkMethod(
                    "qsort",
                    "qsort",
                    List(
                        ParamSpec("base", TypeRef.BufferT(TypeRef.ByteT)),
                        ParamSpec("count", TypeRef.IntT),
                        ParamSpec("elemSize", TypeRef.IntT),
                        ParamSpec("cmp", TypeRef.FnPtrT(List(TypeRef.IntT, TypeRef.IntT), TypeRef.IntT))
                    ),
                    ReturnShape.Void,
                    kind = CallbackKind.Transient
                )
            )
        )
        val src        = JsEmitter.emit(spec)
        val (ok, errs) = ScalaParseProbe.parses(src)
        assert(ok == true, s"emitted source did not parse:\n$src\n\nerrors:\n$errs\n")
    }

    "retained callback: source parses under Scala 3" in {
        val spec = mkTrait(
            "Epoll",
            "kyo_epoll",
            List(
                mkMethod(
                    "epollAdd",
                    "epoll_add",
                    List(
                        ParamSpec("guard", TypeRef.GuardT),
                        ParamSpec("epfd", TypeRef.IntT),
                        ParamSpec("fd", TypeRef.IntT),
                        ParamSpec("onEvent", TypeRef.FnPtrT(List(TypeRef.IntT), TypeRef.UnitT))
                    ),
                    ReturnShape.Primitive(TypeRef.IntT),
                    kind = CallbackKind.Retained
                )
            )
        )
        val src        = JsEmitter.emit(spec)
        val (ok, errs) = ScalaParseProbe.parses(src)
        assert(ok == true, s"emitted source did not parse:\n$src\n\nerrors:\n$errs\n")
    }

    // -------------------------------------------------------------------------
    // Section 4: TcpBindings full fixture
    // -------------------------------------------------------------------------

    "TcpBindings fixture emits all four methods with expected shapes" in {
        val cr = StructSpec(
            "kyo.example.ConnectResult",
            "ConnectResult",
            List(StructField("fd", TypeRef.IntT), StructField("pending", TypeRef.IntT)),
            packed = false
        )
        val spec = mkTrait(
            "TcpBindings",
            "kyo_tcp",
            List(
                mkMethod(
                    "tcpConnect",
                    "tcp_connect",
                    List(ParamSpec("host", TypeRef.StringT), ParamSpec("port", TypeRef.IntT)),
                    ReturnShape.MultiValue(cr),
                    blocking = true
                ),
                mkMethod(
                    "tcpClose",
                    "tcp_close",
                    List(ParamSpec("fd", TypeRef.IntT)),
                    ReturnShape.Void
                ),
                mkMethod(
                    "tcpRead",
                    "tcp_read",
                    List(
                        ParamSpec("fd", TypeRef.IntT),
                        ParamSpec("buf", TypeRef.BufferT(TypeRef.ByteT)),
                        ParamSpec("maxLen", TypeRef.IntT)
                    ),
                    ReturnShape.Primitive(TypeRef.IntT),
                    blocking = true
                ),
                mkMethod(
                    "tcpWrite",
                    "tcp_write",
                    List(
                        ParamSpec("fd", TypeRef.IntT),
                        ParamSpec("buf", TypeRef.BufferT(TypeRef.ByteT)),
                        ParamSpec("len", TypeRef.IntT)
                    ),
                    ReturnShape.Primitive(TypeRef.IntT),
                    blocking = true
                )
            ),
            structs = List(cr)
        )
        val src = JsEmitter.emit(spec)
        assert(src.contains("final class TcpBindingsImpl extends TcpBindings:"))
        // Wildcard import, brings in `facade` plus any callback-proto handles the companion registered.
        assert(src.contains("import TcpBindingsImpl.*"))
        assert(src.contains("end TcpBindingsImpl"))

        // Every binding method takes a trailing `(using kyo.AllowUnsafe)`; the three @Ffi.blocking methods return
        // `kyo.Fiber.Unsafe[…, Any]`; tcpClose is non-blocking and returns a plain value.
        assert(src.contains(
            "def tcpConnect(host: String, port: Int)(using kyo.AllowUnsafe): kyo.Fiber.Unsafe[kyo.example.ConnectResult, Any] ="
        ))
        assert(src.contains("def tcpClose(fd: Int)(using kyo.AllowUnsafe): Unit ="))
        assert(src.contains("def tcpRead(fd: Int, buf: Buffer[Byte], maxLen: Int)(using kyo.AllowUnsafe): kyo.Fiber.Unsafe[Int, Any] ="))
        assert(src.contains("def tcpWrite(fd: Int, buf: Buffer[Byte], len: Int)(using kyo.AllowUnsafe): kyo.Fiber.Unsafe[Int, Any] ="))

        assert(src.contains(
            """KoffiFn("tcpConnect", "tcp_connect", "int", Seq[js.Any]("string".asInstanceOf[js.Any], "int".asInstanceOf[js.Any], "int*".asInstanceOf[js.Any]))"""
        ))
        assert(src.contains("""KoffiFn("tcpClose", "tcp_close", "void", Seq[js.Any]("int".asInstanceOf[js.Any]))"""))
        assert(src.contains(
            """KoffiFn("tcpRead", "tcp_read", "int", Seq[js.Any]("int".asInstanceOf[js.Any], "void*".asInstanceOf[js.Any], "int".asInstanceOf[js.Any]))"""
        ))
        assert(src.contains(
            """KoffiFn("tcpWrite", "tcp_write", "int", Seq[js.Any]("int".asInstanceOf[js.Any], "void*".asInstanceOf[js.Any], "int".asInstanceOf[js.Any]))"""
        ))
    }

