    "non-packed struct is registered via KoffiFacade.struct with field descriptor literal" in {
        val ts = StructSpec(
            "kyo.example.Timespec",
            "Timespec",
            List(StructField("sec", TypeRef.LongT), StructField("nsec", TypeRef.LongT)),
            packed = false
        )
        val spec = mkTrait(
            "Time",
            "kyo_time",
            List(mkMethod(
                "sleep",
                "sleep_ts",
                List(ParamSpec("ts", TypeRef.StructT(ts.fqcn))),
                ReturnShape.Primitive(TypeRef.IntT)
            )),
            structs = List(ts)
        )
        val src = JsEmitter.emit(spec)
        assert(src.contains(
            """KoffiFacade.struct("Timespec", js.Dynamic.literal("sec" -> "int64".asInstanceOf[js.Any], "nsec" -> "int64".asInstanceOf[js.Any]))"""
        ))
        // koffi type for the struct parameter is the simpleName (matching the registered name).
        // Struct param is marshalled as a POINTER ("Timespec*") to mirror the JVM emitter's
        // ADDRESS convention, see comment in JsEmitter.emitKoffiFn for the rationale.
        assert(src.contains("""KoffiFn("sleep", "sleep_ts", "int", Seq[js.Any]("Timespec*".asInstanceOf[js.Any]))"""))
    }

