    // -------------------------------------------------------------------------
    // Section: multi-value out-param call pattern
    // -------------------------------------------------------------------------

    "multi-value return wires up KoffiFacade.outInt/outLong/outPointer allocators per trailing field" in {
        val cr = StructSpec(
            "kyo.example.MV",
            "MV",
            List(
                StructField("code", TypeRef.IntT),   // head (C return)
                StructField("count", TypeRef.IntT),  // int → outInt
                StructField("len", TypeRef.LongT),   // long → outLong
                StructField("name", TypeRef.StringT) // pointer → outPointer
            ),
            packed = false
        )
        val spec = mkTrait(
            "MVFn",
            "kyo_mv",
            List(
                mkMethod("call", "mv_call", Nil, ReturnShape.MultiValue(cr))
            ),
            structs = List(cr)
        )
        val src = JsEmitter.emit(spec)
        // Allocators are emitted one per out-field via the outAllocator mapping.
        assert(src.contains("val countOut = KoffiFacade.outInt()"))
        assert(src.contains("val lenOut = KoffiFacade.outLong()"))
        assert(src.contains("val nameOut = KoffiFacade.outPointer()"))
        // Each cell's `.buf` is passed to facade.call(...) as the trailing out-pointer argument.
        assert(src.contains("facade.call(countOut.buf, lenOut.buf, nameOut.buf)"))
        // Each cell's `.read()` is decoded with the right per-field cast.
        assert(src.contains("countOut.read().asInstanceOf[Int]"))
        assert(src.contains("lenOut.read().asInstanceOf[js.BigInt].toString.toLong"))
        assert(src.contains("nameOut.read().asInstanceOf[String]"))
    }

