        // KoffiFn registration carries the `...` marker as an arg-type entry so koffi treats the call as variadic.
        assert(src.contains(""""...""""))
        // Runtime dispatch helper routes Any values to the appropriate koffi type at call time.
        assert(src.contains("JsVariadicMarshaller"))
